import{_ as a,o as d,c as o,a0 as i}from"./chunks/framework.BVR0KPfW.js";const b=JSON.parse('{"title":"Changelog","description":"","frontmatter":{},"headers":[],"relativePath":"changelog.md","filePath":"changelog.md"}'),t={name:"changelog.md"};function l(n,e,r,c,s,h){return d(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h1><p>All notable changes to oneagent are documented here.</p><h2 id="_0-11-10-2026-03-21" tabindex="-1">[0.11.10] - 2026-03-21 <a class="header-anchor" href="#_0-11-10-2026-03-21" aria-label="Permalink to &quot;[0.11.10] - 2026-03-21&quot;">​</a></h2><h3 id="fixed" tabindex="-1">Fixed <a class="header-anchor" href="#fixed" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>Empty inline-assignment template args like <code>-c model_reasoning_effort={thinking}</code> now drop cleanly when the placeholder is unset instead of leaving invalid backend-specific fragments behind.</li></ul><h2 id="_0-11-9-2026-03-20" tabindex="-1">[0.11.9] - 2026-03-20 <a class="header-anchor" href="#_0-11-9-2026-03-20" aria-label="Permalink to &quot;[0.11.9] - 2026-03-20&quot;">​</a></h2><h3 id="fixed-1" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-1" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>Backends that exit non-zero but produce a valid result (e.g. Cline exits 1 on success) are now treated as successful instead of overwriting the result with an error.</li></ul><h2 id="_0-11-8-2026-03-20" tabindex="-1">[0.11.8] - 2026-03-20 <a class="header-anchor" href="#_0-11-8-2026-03-20" aria-label="Permalink to &quot;[0.11.8] - 2026-03-20&quot;">​</a></h2><h3 id="added" tabindex="-1">Added <a class="header-anchor" href="#added" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><code>Thinking</code> field on <code>RunOpts</code> and <code>--thinking &lt;level&gt;</code> CLI flag for controlling thinking/reasoning effort per invocation.</li><li><code>{thinking}</code> template variable in backend configs — drops silently when unset.</li><li>Thinking support in Claude (<code>--effort</code>), Codex (<code>-c model_reasoning_effort=</code>), and Pi (<code>--thinking</code>) embedded configs.</li></ul><h2 id="_0-11-7-2026-03-20" tabindex="-1">[0.11.7] - 2026-03-20 <a class="header-anchor" href="#_0-11-7-2026-03-20" aria-label="Permalink to &quot;[0.11.7] - 2026-03-20&quot;">​</a></h2><h3 id="added-1" tabindex="-1">Added <a class="header-anchor" href="#added-1" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><code>RunContext</code> and <code>RunStreamContext</code> methods on <code>Client</code> and package level for cancellable backend invocations via <code>context.Context</code>.</li><li><code>ExitCode</code> and <code>Stderr</code> fields on <code>Response</code> for richer error diagnostics.</li><li>Negative array index support in <code>jsonGet</code> (e.g., <code>content.-1.text</code> for last element).</li></ul><h3 id="fixed-2" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-2" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>Pi backend empty result when model includes thinking tokens before text content — now uses <code>turn_end</code> with <code>content.-1.text</code>.</li><li>Session backfill on resume — <code>resp.Session</code> is populated from <code>opts.SessionID</code> when no session event arrives from the backend.</li></ul><h2 id="_0-11-6-2026-03-20" tabindex="-1">[0.11.6] - 2026-03-20 <a class="header-anchor" href="#_0-11-6-2026-03-20" aria-label="Permalink to &quot;[0.11.6] - 2026-03-20&quot;">​</a></h2><h3 id="fixed-3" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-3" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>Empty successful backend results are now preserved as empty strings instead of being rewritten to <code>Done — nothing to report.</code></li></ul><h2 id="_0-11-5-2026-03-20" tabindex="-1">[0.11.5] - 2026-03-20 <a class="header-anchor" href="#_0-11-5-2026-03-20" aria-label="Permalink to &quot;[0.11.5] - 2026-03-20&quot;">​</a></h2><h3 id="added-2" tabindex="-1">Added <a class="header-anchor" href="#added-2" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><code>LoadBackendsWithOptions</code> and <code>LoadOptions</code> for consumers that want embedded defaults plus an app-owned override path instead of <code>~/.config/oneagent/backends.json</code>.</li></ul><h3 id="fixed-4" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-4" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>Pi backend result selection now uses the final assistant message while keeping <code>text_delta</code> streaming separate, preventing intermediate narration from being folded into the final result.</li></ul><h2 id="_0-11-4-2026-03-20" tabindex="-1">[0.11.4] - 2026-03-20 <a class="header-anchor" href="#_0-11-4-2026-03-20" aria-label="Permalink to &quot;[0.11.4] - 2026-03-20&quot;">​</a></h2><h3 id="added-3" tabindex="-1">Added <a class="header-anchor" href="#added-3" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>Embedded Gemini CLI backend with stream-json output parsing.</li></ul><h3 id="changed" tabindex="-1">Changed <a class="header-anchor" href="#changed" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li>Removed <code>--skills</code> references from <code>oa-dispatch</code> skill.</li></ul><h2 id="_0-11-3-2026-03-19" tabindex="-1">[0.11.3] - 2026-03-19 <a class="header-anchor" href="#_0-11-3-2026-03-19" aria-label="Permalink to &quot;[0.11.3] - 2026-03-19&quot;">​</a></h2><h3 id="added-4" tabindex="-1">Added <a class="header-anchor" href="#added-4" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>golangci-lint config (<code>.golangci.yml</code>) and pre-commit hook.</li></ul><h3 id="changed-1" tabindex="-1">Changed <a class="header-anchor" href="#changed-1" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li>Cyclomatic complexity threshold relaxed from 10 to 15.</li><li><code>buildCmd</code> refactored into smaller helpers for readability.</li></ul><h3 id="fixed-5" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-5" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>Unchecked <code>f.Close()</code> error in thread loading.</li></ul><h2 id="_0-11-2-2026-03-19" tabindex="-1">[0.11.2] - 2026-03-19 <a class="header-anchor" href="#_0-11-2-2026-03-19" aria-label="Permalink to &quot;[0.11.2] - 2026-03-19&quot;">​</a></h2><h3 id="fixed-6" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-6" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>Activity events for claude, opencode, and pi backends now include tool context (description, command, title) instead of just the tool name.</li></ul><h3 id="changed-2" tabindex="-1">Changed <a class="header-anchor" href="#changed-2" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li><code>oa-dispatch</code> skill uses pipe form for all prompts.</li></ul><h2 id="_0-11-1-2026-03-18" tabindex="-1">[0.11.1] - 2026-03-18 <a class="header-anchor" href="#_0-11-1-2026-03-18" aria-label="Permalink to &quot;[0.11.1] - 2026-03-18&quot;">​</a></h2><h3 id="fixed-7" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-7" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><strong>Security</strong>: Thread ID path traversal — IDs containing <code>../</code> or path separators are now rejected, preventing writes outside the thread directory.</li><li>Thread saves are now atomic — writes to a temp file then renames, preventing corruption on crash.</li><li><code>cwd</code> check in <code>buildCmd</code> now uses the active template (run or resume) instead of always checking the run template.</li><li><code>PostRun</code> callback now receives the original user prompt, not the replay-expanded version with thread context.</li><li>Scanner errors in JSONL parsing are now always logged, even when the backend also exits non-zero.</li></ul><h3 id="added-5" tabindex="-1">Added <a class="header-anchor" href="#added-5" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>Example scripts: multi-agent conversation, self-healing tests, parallel review, daily digest.</li><li><code>converse.sh</code> and <code>multi-review.sh</code> bundled in the <code>oa-dispatch</code> agent skill.</li></ul><h2 id="_0-11-0-2026-03-18" tabindex="-1">[0.11.0] - 2026-03-18 <a class="header-anchor" href="#_0-11-0-2026-03-18" aria-label="Permalink to &quot;[0.11.0] - 2026-03-18&quot;">​</a></h2><h3 id="added-6" tabindex="-1">Added <a class="header-anchor" href="#added-6" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>Pre/post hook system — run commands or Go callbacks before and after agent execution. Config-level hooks fire on every backend invocation, CLI hooks (<code>--pre-run</code>/<code>--post-run</code>) are per-invocation. Both layers stack.</li><li>Library-level hook callbacks: <code>PreRun func(*RunOpts) error</code> can modify options or abort, <code>PostRun func(*HookContext)</code> for side effects.</li><li><code>HookContext</code> type exposing both <code>RunOpts</code> and <code>Response</code> to post-run callbacks.</li><li>Internal calls (e.g., <code>CompactThread</code>) bypass hooks via <code>runDirect()</code>.</li></ul><h3 id="removed" tabindex="-1">Removed <a class="header-anchor" href="#removed" aria-label="Permalink to &quot;Removed&quot;">​</a></h3><ul><li>Legacy completion hook field/flag — replaced by the general <code>PostRunCmd</code>/<code>--post-run</code> hook.</li></ul><h2 id="_0-10-7-2026-03-18" tabindex="-1">[0.10.7] - 2026-03-18 <a class="header-anchor" href="#_0-10-7-2026-03-18" aria-label="Permalink to &quot;[0.10.7] - 2026-03-18&quot;">​</a></h2><h3 id="added-7" tabindex="-1">Added <a class="header-anchor" href="#added-7" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><code>prompt_stdin</code> config field — pass prompts via stdin instead of command-line arguments, keeping prompt content out of <code>ps</code> output. All four embedded backends now use this by default.</li></ul><h2 id="_0-10-6-2026-03-17" tabindex="-1">[0.10.6] - 2026-03-17 <a class="header-anchor" href="#_0-10-6-2026-03-17" aria-label="Permalink to &quot;[0.10.6] - 2026-03-17&quot;">​</a></h2><h3 id="added-8" tabindex="-1">Added <a class="header-anchor" href="#added-8" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>Stdin pipe support — pipe content into <code>oa</code> as context, with optional positional args as instructions. Examples: <code>cat file.go | oa -b claude &quot;review this&quot;</code>, <code>git diff | oa -b claude &quot;explain these changes&quot;</code>.</li><li><code>oa backends</code> alias for <code>oa list</code>.</li><li>Docs site now auto-rebuilds after every release so the version badge stays current.</li></ul><h2 id="_0-10-5-2026-03-17" tabindex="-1">[0.10.5] - 2026-03-17 <a class="header-anchor" href="#_0-10-5-2026-03-17" aria-label="Permalink to &quot;[0.10.5] - 2026-03-17&quot;">​</a></h2><h3 id="added-9" tabindex="-1">Added <a class="header-anchor" href="#added-9" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><code>paths</code> config field — additional directories to search when a backend CLI isn&#39;t in <code>$PATH</code>. Supports <code>~</code> expansion. Embedded defaults ship with known install locations for each backend.</li><li>Troubleshooting doc with PATH and config-based fixes for missing backends.</li><li>Improved error message when a backend CLI is not found, with a link to the troubleshooting guide.</li></ul><h3 id="changed-3" tabindex="-1">Changed <a class="header-anchor" href="#changed-3" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li><code>oa list</code> output cleaned up: no redundant program name or format column, only shows model when explicitly set, marks unavailable backends with <code>(not installed)</code>.</li></ul><h2 id="_0-10-4-2026-03-17" tabindex="-1">[0.10.4] - 2026-03-17 <a class="header-anchor" href="#_0-10-4-2026-03-17" aria-label="Permalink to &quot;[0.10.4] - 2026-03-17&quot;">​</a></h2><h3 id="changed-4" tabindex="-1">Changed <a class="header-anchor" href="#changed-4" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li><code>oa list</code> now shows <code>(not installed)</code> for backends whose CLI is not found in PATH.</li><li>Switched Homebrew distribution from cask to formula — no more Gatekeeper issues on macOS.</li><li>Install with <code>brew install 1broseidon/tap/oa</code>.</li></ul><h2 id="_0-10-3-2026-03-17" tabindex="-1">[0.10.3] - 2026-03-17 <a class="header-anchor" href="#_0-10-3-2026-03-17" aria-label="Permalink to &quot;[0.10.3] - 2026-03-17&quot;">​</a></h2><h3 id="fixed-8" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-8" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>Codex backend now uses <code>--dangerously-bypass-approvals-and-sandbox</code> instead of <code>--full-auto</code> — bubblewrap sandbox fails on some kernels, blocking all writes.</li></ul><h2 id="_0-10-2-2026-03-17" tabindex="-1">[0.10.2] - 2026-03-17 <a class="header-anchor" href="#_0-10-2-2026-03-17" aria-label="Permalink to &quot;[0.10.2] - 2026-03-17&quot;">​</a></h2><h3 id="added-10" tabindex="-1">Added <a class="header-anchor" href="#added-10" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>File locking on thread storage — <code>LoadThread</code> acquires a shared lock, <code>SaveThread</code> acquires an exclusive lock, preventing corruption when multiple processes (e.g., a bot and a cron job) access the same thread concurrently.</li><li>Turn attribution — <code>Turn.Source</code> field and <code>RunOpts.Source</code> let callers tag who produced a turn (e.g., <code>&quot;telegram&quot;</code>, <code>&quot;cron-nightly&quot;</code>, <code>&quot;ci-pipeline&quot;</code>).</li><li>Post-run hooks — <code>RunOpts.PostRunCmd</code> and <code>--post-run</code> execute a command after a thread turn completes, with the result piped to stdin and <code>OA_THREAD_ID</code>, <code>OA_BACKEND</code>, <code>OA_SESSION</code>, <code>OA_SOURCE</code> set as environment variables. Best-effort: hook failures are logged but don&#39;t fail the response.</li></ul><h2 id="_0-10-1-2026-03-16" tabindex="-1">[0.10.1] - 2026-03-16 <a class="header-anchor" href="#_0-10-1-2026-03-16" aria-label="Permalink to &quot;[0.10.1] - 2026-03-16&quot;">​</a></h2><h3 id="added-11" tabindex="-1">Added <a class="header-anchor" href="#added-11" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>Activity events for the OpenCode backend — tool use (file reads, patches) now appears in JSONL streaming output.</li><li><code>oa-dispatch</code> agent skill for dispatching tasks to other agents, following the <a href="https://agentskills.io" target="_blank" rel="noreferrer">agentskills.io</a> spec. Install with <code>npx skills add 1broseidon/oneagent --skill oa-dispatch</code>.</li></ul><h3 id="improved" tabindex="-1">Improved <a class="header-anchor" href="#improved" aria-label="Permalink to &quot;Improved&quot;">​</a></h3><ul><li>Rewrote all public-facing docs for clarity and correctness: README, library guide, config reference, integration example, and changelog.</li><li>README now leads with a clear value proposition and includes prerequisites.</li><li>Library docs updated to use the Client-based API introduced in 0.9.0.</li><li>Integration example replaced with a complete, runnable <code>main.go</code>.</li><li>Config docs include all four backend examples with verified minimum flags for non-interactive execution.</li></ul><h3 id="fixed-9" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-9" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>Claude backend now includes <code>--dangerously-skip-permissions</code> — required for write and bash operations since <code>-p</code> mode only permits reads.</li></ul><h2 id="_0-10-0-2026-03-16" tabindex="-1">[0.10.0] - 2026-03-16 <a class="header-anchor" href="#_0-10-0-2026-03-16" aria-label="Permalink to &quot;[0.10.0] - 2026-03-16&quot;">​</a></h2><h3 id="added-12" tabindex="-1">Added <a class="header-anchor" href="#added-12" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>GoReleaser configuration and a tag-driven GitHub Actions release workflow.</li><li>Homebrew tap publishing configuration targeting <code>1broseidon/homebrew-tap</code>.</li><li><code>oa --version</code> and <code>oa version</code> for release verification and package-manager smoke tests.</li></ul><h2 id="_0-9-0-2026-03-16" tabindex="-1">[0.9.0] - 2026-03-16 <a class="header-anchor" href="#_0-9-0-2026-03-16" aria-label="Permalink to &quot;[0.9.0] - 2026-03-16&quot;">​</a></h2><h3 id="added-13" tabindex="-1">Added <a class="header-anchor" href="#added-13" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>Pluggable thread storage through a <code>Store</code> interface — use the built-in filesystem store or bring your own.</li><li><code>Client</code> type for applications that embed oneagent, with methods for running, streaming, and managing threads.</li></ul><h2 id="_0-8-0-2026-03-16" tabindex="-1">[0.8.0] - 2026-03-16 <a class="header-anchor" href="#_0-8-0-2026-03-16" aria-label="Permalink to &quot;[0.8.0] - 2026-03-16&quot;">​</a></h2><h3 id="changed-5" tabindex="-1">Changed <a class="header-anchor" href="#changed-5" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li>Plain text is now the default CLI output mode. Use <code>--json</code> for machine-readable output.</li><li>Added <code>--jsonl</code> as a shortcut for <code>--stream --json</code>.</li></ul><h3 id="added-14" tabindex="-1">Added <a class="header-anchor" href="#added-14" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>Dedicated docs for library usage, backend config, and integration examples.</li></ul><h2 id="_0-7-0-2026-03-15" tabindex="-1">[0.7.0] - 2026-03-15 <a class="header-anchor" href="#_0-7-0-2026-03-15" aria-label="Permalink to &quot;[0.7.0] - 2026-03-15&quot;">​</a></h2><h3 id="added-15" tabindex="-1">Added <a class="header-anchor" href="#added-15" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>Generic <code>activity</code> events in normalized streaming output, showing what the agent is doing (e.g., reading a file, running a command).</li></ul><h2 id="_0-6-0-2026-03-15" tabindex="-1">[0.6.0] - 2026-03-15 <a class="header-anchor" href="#_0-6-0-2026-03-15" aria-label="Permalink to &quot;[0.6.0] - 2026-03-15&quot;">​</a></h2><h3 id="added-16" tabindex="-1">Added <a class="header-anchor" href="#added-16" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>Embedded default backends for Claude, Codex, OpenCode, and Pi — works on first run with no config file.</li><li>Normalized JSONL streaming in both the CLI and Go library.</li></ul><h2 id="_0-5-0-2026-03-15" tabindex="-1">[0.5.0] - 2026-03-15 <a class="header-anchor" href="#_0-5-0-2026-03-15" aria-label="Permalink to &quot;[0.5.0] - 2026-03-15&quot;">​</a></h2><h3 id="added-17" tabindex="-1">Added <a class="header-anchor" href="#added-17" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>Compact backend config format — define backends in concise JSON instead of writing Go code.</li></ul><h2 id="_0-4-0-2026-03-15" tabindex="-1">[0.4.0] - 2026-03-15 <a class="header-anchor" href="#_0-4-0-2026-03-15" aria-label="Permalink to &quot;[0.4.0] - 2026-03-15&quot;">​</a></h2><h3 id="added-18" tabindex="-1">Added <a class="header-anchor" href="#added-18" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>Portable threads for cross-backend conversation continuity.</li><li>Thread listing, inspection, and compaction commands.</li></ul><h2 id="_0-2-0-2026-03-15" tabindex="-1">[0.2.0] - 2026-03-15 <a class="header-anchor" href="#_0-2-0-2026-03-15" aria-label="Permalink to &quot;[0.2.0] - 2026-03-15&quot;">​</a></h2><h3 id="changed-6" tabindex="-1">Changed <a class="header-anchor" href="#changed-6" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li>Improved public API surface and documentation.</li></ul><h2 id="_0-1-0-2026-03-15" tabindex="-1">[0.1.0] - 2026-03-15 <a class="header-anchor" href="#_0-1-0-2026-03-15" aria-label="Permalink to &quot;[0.1.0] - 2026-03-15&quot;">​</a></h2><h3 id="added-19" tabindex="-1">Added <a class="header-anchor" href="#added-19" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>Initial release: config-driven multi-agent CLI with normalized JSON output and session resume.</li></ul>',107)])])}const f=a(t,[["render",l]]);export{b as __pageData,f as default};
